import { ipcRenderer } from "electron";
import { mapState } from "vuex";
export default {
  computed: mapState({
    loggedin: state => state.token != ""
  }),
  methods: {
    minimizeApp() {
      ipcRenderer.send("minimizeApp");
    },
    closeApp() {
      ipcRenderer.send("closeApp");
    },
    logoutModal() {
      this.$modal.logout.show();
    }
  }
};
